import { workflow, node, trigger } from '@n8n/workflow-sdk';

const manual_Trigger = trigger({
  type: 'n8n-nodes-base.manualTrigger',
  version: 1,
  config: { name: 'Manual Trigger' }
});

const ndv_output_test = node({
  type: 'n8n-nodes-base.set',
  version: 3.4,
  config: { name: 'ndv output test', parameters: { assignments: { assignments: [{ id: 'status-assignment', name: 'status', value: 'ready', type: 'string' }] }, options: {} } }
});

const ndv_output_test_terminal = node({
  type: 'n8n-nodes-base.noOp',
  version: 1,
  config: { name: 'ndv output test terminal' }
});

const wf = workflow('Rh1PPWPu1izf7KXq', 'NDV Output Workflow');

export default wf
  .add(manual_Trigger)
  .to(ndv_output_test)
  .to(ndv_output_test_terminal)
